   301→    function HomeScreen({ budgets, setBudgets, onSelect }) {
   302→      const [mode, setMode]         = useState("list"); // list | add | edit
   303→      const [editingId, setEditingId] = useState(null);
   304→
   305→      const addBudget = (form) => {
   306→        const b = {
   307→          id: Date.now(),
   308→          name: form.name.trim(),
   309→          className: form.className.trim(),
   310→          year: form.year.trim(),
   311→          colorKey: form.colorKey,
   312→          feePerStudent: Number(form.feePerStudent) || 500,
   313→          students: [], events: [], cashLog: [], gifts: [],
   314→        };
   315→        setBudgets(prev => [...prev, b]);
   316→        setMode("list");
   317→      };
   318→
   319→      const saveBudget = (form) => {
   320→        setBudgets(prev => prev.map(b => b.id === editingId
   321→          ? { ...b, name: form.name.trim(), className: form.className.trim(), year: form.year.trim(), colorKey: form.colorKey, feePerStudent: Number(form.feePerStudent) || b.feePerStudent }
   322→          : b
   323→        ));
   324→        setMode("list"); setEditingId(null);
   325→      };
   326→
   327→      const deleteBudget = (id) => {
   328→        if (window.confirm("למחוק תקציב זה? הנתונים יאבדו לצמיתות.")) {
   329→          setBudgets(prev => prev.filter(b => b.id !== id));
   330→        }
   331→      };
   332→
   333→      const editingBudget = budgets.find(b => b.id === editingId);
   334→
   335→      return (
   336→        <div style={{ minHeight: "100vh", background: "#f8fafc" }}>
   337→          {/* Header */}
   338→          <div style={{
   339→            background: "linear-gradient(135deg, #1e293b 0%, #0f172a 100%)",
   340→            padding: "24px 20px 28px",
   341→          }}>
   342→            <div style={{ color: "rgba(255,255,255,0.5)", fontSize: 12, fontWeight: 600, letterSpacing: 1, textTransform: "uppercase", marginBottom: 6 }}>מנהל תקציבים</div>
   343→            <div style={{ color: "white", fontWeight: 900, fontSize: 24 }}>ועד הורים 🏫</div>
   344→            <div style={{ color: "rgba(255,255,255,0.6)", fontSize: 13, marginTop: 4 }}>בחרי תקציב לניהול</div>
   345→          </div>
   346→
   347→          <div style={{ padding: "20px 14px 30px" }}>
   348→            {mode === "add" && (
   349→              <BudgetForm title="➕ תקציב חדש" onSave={addBudget} onCancel={() => setMode("list")} />
   350→            )}
   351→            {mode === "edit" && editingBudget && (
   352→              <BudgetForm
   353→                title="✏️ עריכת תקציב"
   354→                initial={{ ...editingBudget, feePerStudent: String(editingBudget.feePerStudent) }}
   355→                onSave={saveBudget}
   356→                onCancel={() => { setMode("list"); setEditingId(null); }}
   357→              />
   358→            )}
   359→
   360→            {budgets.length === 0 && mode === "list" && (
   361→              <div style={{ textAlign: "center", color: "#94a3b8", padding: "40px 0" }}>
   362→                <div style={{ fontSize: 40, marginBottom: 12 }}>📋</div>
   363→                <div style={{ fontSize: 15, fontWeight: 600 }}>אין תקציבים עדיין</div>
   364→                <div style={{ fontSize: 13, marginTop: 4 }}>לחצי על הכפתור למטה כדי להוסיף</div>
   365→              </div>
   366→            )}
   367→
   368→            {mode === "list" && budgets.map(b => (
   369→              <BudgetListCard
   370→                key={b.id}
   371→                budget={b}
   372→                onSelect={() => onSelect(b.id)}
   373→                onEdit={() => { setEditingId(b.id); setMode("edit"); }}
   374→                onDelete={() => deleteBudget(b.id)}
   375→              />
   376→            ))}
   377→
   378→            {mode === "list" && (
   379→              <button onClick={() => setMode("add")} style={{
   380→                width: "100%", padding: 16, borderRadius: 16, border: "2px dashed #cbd5e1",
   381→                background: "transparent", color: "#7c3aed", fontWeight: 700, fontSize: 14,
   382→                cursor: "pointer", fontFamily: "inherit",
   383→              }}>+ הוסיפי תקציב חדש</button>
   384→            )}
   385→          </div>
   386→        </div>
   387→      );
   388→    }
