   391→    // BUDGET TAB — Events with edit
   392→    // ─────────────────────────────────────────
   393→    const EMPTY_EVENT = { name: "", date: "", budget: "", spent: "", category: "פעילות", notes: "", paidBy: "", done: false };
   394→
   395→    function BudgetTab({ events, setEvents }) {
   396→      const [showAdd, setShowAdd] = useState(false);
   397→      const [filter, setFilter]  = useState("הכל");
   398→      const [addForm, setAddForm] = useState(EMPTY_EVENT);
   399→      const [editId, setEditId]  = useState(null);
   400→      const [editForm, setEditForm] = useState({});
   401→
   402→      const totalBudget = events.reduce((s, e) => s + e.budget, 0);
   403→      const totalSpent  = events.reduce((s, e) => s + e.spent,  0);
   404→      const cats        = ["הכל", ...CAT_LIST];
   405→      const filtered    = filter === "הכל" ? events : events.filter(e => e.category === filter);
   406→
   407→      const addEvent = () => {
   408→        if (!addForm.name.trim()) return;
   409→        setEvents([...events, { id: Date.now(), ...addForm, budget: Number(addForm.budget) || 0, spent: Number(addForm.spent) || 0 }]);
   410→        setAddForm(EMPTY_EVENT); setShowAdd(false);
   411→      };
   412→
   413→      const startEdit = (ev) => { setEditId(ev.id); setEditForm({ ...ev, budget: String(ev.budget), spent: String(ev.spent) }); };
   414→      const cancelEdit = () => setEditId(null);
   415→      const saveEdit = () => {
   416→        setEvents(events.map(e => e.id === editId ? { ...editForm, id: editId, budget: Number(editForm.budget) || 0, spent: Number(editForm.spent) || 0 } : e));
   417→        setEditId(null);
   418→      };
   419→      const removeEvent = (id) => { if (window.confirm("למחוק ארוע זה?")) setEvents(events.filter(e => e.id !== id)); };
   420→      const toggleDone  = (id) => setEvents(events.map(e => e.id === id ? { ...e, done: !e.done } : e));
   421→
   422→      const EventForm = ({ data, onChange, onSave, onCancel, title }) => (
   423→        <Card style={{ border: "2px solid #ede9fe" }}>
   424→          <div style={{ fontWeight: 700, marginBottom: 10, fontSize: 14 }}>{title}</div>
   425→          <FieldLabel>שם הארוע *</FieldLabel>
   426→          <input value={data.name} onChange={e => onChange({ ...data, name: e.target.value })} placeholder="שם הארוע" style={S.input} autoFocus />
   427→          <FieldLabel>תאריך</FieldLabel>
   428→          <input value={data.date} onChange={e => onChange({ ...data, date: e.target.value })} placeholder="תאריך" style={S.input} />
   429→          <div style={{ display: "flex", gap: 8 }}>
   430→            <div style={{ flex: 1 }}>
   431→              <FieldLabel>תקציב ₪</FieldLabel>
   432→              <input type="number" value={data.budget} onChange={e => onChange({ ...data, budget: e.target.value })} placeholder="0" style={S.input} />
   433→            </div>
   434→            <div style={{ flex: 1 }}>
   435→              <FieldLabel>שולם ₪</FieldLabel>
   436→              <input type="number" value={data.spent} onChange={e => onChange({ ...data, spent: e.target.value })} placeholder="0" style={S.input} />
   437→            </div>
   438→          </div>
   439→          <FieldLabel>קטגוריה</FieldLabel>
   440→          <select value={data.category} onChange={e => onChange({ ...data, category: e.target.value })} style={S.input}>
   441→            {CAT_LIST.map(c => <option key={c}>{c}</option>)}
   442→          </select>
   443→          <FieldLabel>הערות</FieldLabel>
   444→          <input value={data.notes} onChange={e => onChange({ ...data, notes: e.target.value })} placeholder="הערות" style={S.input} />
   445→          <FieldLabel>שולם ע״י</FieldLabel>
   446→          <input value={data.paidBy || ""} onChange={e => onChange({ ...data, paidBy: e.target.value })} placeholder="שולם ע״י" style={S.input} />
   447→          <label style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 12, cursor: "pointer", fontSize: 13 }}>
   448→            <input type="checkbox" checked={!!data.done} onChange={e => onChange({ ...data, done: e.target.checked })} style={{ width: 16, height: 16 }} />
   449→            הושלם ✅
   450→          </label>
   451→          <div style={{ display: "flex", gap: 8 }}>
   452→            <button onClick={onSave} style={S.btn("#7c3aed")} disabled={!data.name.trim()}>שמור</button>
   453→            <button onClick={onCancel} style={S.btn("#94a3b8")}>ביטול</button>
   454→          </div>
   455→        </Card>
   456→      );
   457→
   458→      return (
   459→        <div>
   460→          {/* Summary */}
   461→          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 8, marginBottom: 16 }}>
   462→            {[
   463→              { l: "תקציב כולל", v: `₪${totalBudget.toLocaleString()}`, c: "#7c3aed" },
   464→              { l: "שולם",       v: `₪${totalSpent.toLocaleString()}`,   c: "#db2777" },
   465→              { l: "נשאר",       v: `₪${(totalBudget - totalSpent).toLocaleString()}`, c: "#059669" },
   466→            ].map(x => (
   467→              <div key={x.l} style={{ background: "white", borderRadius: 14, padding: "12px 8px", textAlign: "center", boxShadow: "0 2px 10px rgba(0,0,0,0.07)" }}>
   468→                <div style={{ fontWeight: 900, fontSize: 16, color: x.c }}>{x.v}</div>
   469→                <div style={{ fontSize: 10, color: "#94a3b8" }}>{x.l}</div>
   470→              </div>
   471→            ))}
   472→          </div>
   473→
   474→          {/* Filters */}
   475→          <div style={{ display: "flex", gap: 6, overflowX: "auto", marginBottom: 14, paddingBottom: 2 }}>
   476→            {cats.map(c => (
   477→              <button key={c} onClick={() => setFilter(c)} style={{
   478→                padding: "6px 12px", borderRadius: 20, border: "none", cursor: "pointer",
   479→                fontFamily: "inherit", fontWeight: 600, fontSize: 12, whiteSpace: "nowrap",
   480→                background: filter === c ? "#7c3aed" : "#f1f5f9",
   481→                color:      filter === c ? "white"   : "#64748b",
   482→              }}>{c}</button>
   483→            ))}
   484→          </div>
   485→
   486→          {/* Event list */}
   487→          {filtered.map(ev => (
   488→            editId === ev.id ? (
   489→              <EventForm key={ev.id} title="✏️ עריכת ארוע" data={editForm} onChange={setEditForm} onSave={saveEdit} onCancel={cancelEdit} />
   490→            ) : (
   491→              <Card key={ev.id} style={{ opacity: ev.done ? 0.65 : 1, padding: "12px 14px" }}>
   492→                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
   493→                  <div style={{ flex: 1, minWidth: 0 }}>
   494→                    <div style={{ display: "flex", alignItems: "center", gap: 6, marginBottom: 4 }}>
   495→                      <button onClick={() => toggleDone(ev.id)} style={{ background: "none", border: "none", cursor: "pointer", fontSize: 16, padding: 0, lineHeight: 1 }}>
   496→                        {ev.done ? "✅" : "⬜"}
   497→                      </button>
   498→                      <span style={{ fontWeight: 700, fontSize: 14, color: "#0f172a" }}>{ev.name}</span>
   499→                    </div>
   500→                    <div style={{ display: "flex", gap: 6, alignItems: "center", marginBottom: 4, flexWrap: "wrap" }}>
   501→                      <Badge text={ev.category} cat={ev.category} />
   502→                      <span style={{ fontSize: 11, color: "#94a3b8" }}>{ev.date}</span>
   503→                      {ev.paidBy && <span style={{ fontSize: 11, color: "#94a3b8" }}>• {ev.paidBy}</span>}
   504→                    </div>
   505→                    {ev.notes && <div style={{ fontSize: 11, color: "#64748b" }}>📝 {ev.notes}</div>}
   506→                  </div>
   507→                  <div style={{ textAlign: "left", flexShrink: 0, marginRight: 8 }}>
   508→                    <div style={{ fontWeight: 900, fontSize: 16, color: "#0f172a" }}>₪{ev.budget.toLocaleString()}</div>
   509→                    <div style={{ fontSize: 10, color: "#94a3b8" }}>תקציב</div>
   510→                    {ev.spent > 0 && <div style={{ fontSize: 12, fontWeight: 700, color: "#db2777", marginTop: 2 }}>₪{ev.spent.toLocaleString()} שולם</div>}
   511→                  </div>
   512→                </div>
   513→                {ev.spent > 0 && ev.budget > 0 && (
   514→                  <ProgressBar
   515→                    pct={(ev.spent / ev.budget) * 100}
   516→                    color={(ev.spent / ev.budget) > 1 ? "#ef4444" : (ev.spent / ev.budget) > 0.8 ? "#f59e0b" : "#7c3aed"}
   517→                    style={{ marginTop: 8, marginBottom: 4 }}
   518→                  />
   519→                )}
   520→                <div style={{ display: "flex", gap: 6, marginTop: 8 }}>
   521→                  <button onClick={() => startEdit(ev)} style={S.smallBtn("#e2e8f0", "#64748b")}>✏️ ערכי</button>
   522→                  <button onClick={() => removeEvent(ev.id)} style={S.smallBtn("#fee2e2", "#ef4444")}>✕ מחקי</button>
   523→                </div>
   524→              </Card>
   525→            )
   526→          ))}
   527→
   528→          {/* Add form */}
   529→          {showAdd ? (
   530→            <EventForm title="➕ ארוע חדש" data={addForm} onChange={setAddForm} onSave={addEvent} onCancel={() => setShowAdd(false)} />
   531→          ) : (
   532→            <button onClick={() => setShowAdd(true)} style={{
   533→              width: "100%", padding: 14, borderRadius: 14, border: "2px dashed #e2e8f0",
   534→              background: "transparent", color: "#7c3aed", fontWeight: 700, fontSize: 14,
   535→              cursor: "pointer", fontFamily: "inherit",
   536→            }}>+ הוסיפי ארוע</button>
   537→          )}
   538→        </div>
   539→      );
   540→    }
