   542→    // ─────────────────────────────────────────
   543→    // COLLECT TAB — Students with edit
   544→    // ─────────────────────────────────────────
   545→    function CollectTab({ students, setStudents, feePerStudent = 500 }) {
   546→      const [search,   setSearch]   = useState("");
   547→      const [showAdd,  setShowAdd]  = useState(false);
   548→      const [newName,  setNewName]  = useState("");
   549→      const [editId,   setEditId]   = useState(null);
   550→      const [editForm, setEditForm] = useState({});
   551→
   552→      const paidCount      = students.filter(s => s.paid).length;
   553→      const totalCollected = students.reduce((s, st) => s + (st.amount || 0), 0);
   554→      const filtered       = search ? students.filter(s => s.name.includes(search)) : students;
   555→
   556→      const toggle = (id) => setStudents(students.map(s =>
   557→        s.id === id ? { ...s, paid: !s.paid, amount: !s.paid ? feePerStudent : s.amount } : s
   558→      ));
   559→
   560→      const addStudent = () => {
   561→        if (!newName.trim()) return;
   562→        setStudents([...students, { id: Date.now(), name: newName.trim(), paid: false, amount: 0, note: "" }]);
   563→        setNewName(""); setShowAdd(false);
   564→      };
   565→
   566→      const startEdit = (s) => { setEditId(s.id); setEditForm({ ...s, amount: String(s.amount) }); };
   567→      const cancelEdit = () => setEditId(null);
   568→      const saveEdit = () => {
   569→        setStudents(students.map(s => s.id === editId
   570→          ? { ...editForm, id: editId, amount: Number(editForm.amount) || 0, paid: !!editForm.paid }
   571→          : s
   572→        ));
   573→        setEditId(null);
   574→      };
   575→      const removeStudent = (id) => { if (window.confirm("למחוק תלמיד זה?")) setStudents(students.filter(s => s.id !== id)); };
   576→
   577→      return (
   578→        <div>
   579→          {/* Stats */}
   580→          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 8, marginBottom: 16 }}>
   581→            {[
   582→              { l: "שילמו",    v: paidCount,                            c: "#059669", icon: "✅" },
   583→              { l: "לא שילמו", v: students.length - paidCount,          c: "#ef4444", icon: "❌" },
   584→              { l: "נגבה",     v: `₪${totalCollected.toLocaleString()}`, c: "#7c3aed", icon: "💰" },
   585→            ].map(x => (
   586→              <div key={x.l} style={{ background: "white", borderRadius: 14, padding: "12px 8px", textAlign: "center", boxShadow: "0 2px 10px rgba(0,0,0,0.07)" }}>
   587→                <div style={{ fontSize: 18 }}>{x.icon}</div>
   588→                <div style={{ fontWeight: 900, fontSize: 18, color: x.c }}>{x.v}</div>
   589→                <div style={{ fontSize: 10, color: "#94a3b8" }}>{x.l}</div>
   590→              </div>
   591→            ))}
   592→          </div>
   593→
   594→          <input placeholder="🔍 חפשי תלמיד..." value={search}
   595→            onChange={e => setSearch(e.target.value)} style={{ ...S.input, marginBottom: 10 }} />
   596→
   597→          {students.length > 0 && (
   598→            <>
   599→              <ProgressBar pct={(paidCount / students.length) * 100} color="linear-gradient(90deg,#059669,#7c3aed)" />
   600→              <div style={{ display: "flex", justifyContent: "space-between", fontSize: 11, color: "#94a3b8", marginBottom: 14, marginTop: 4 }}>
   601→                <span>0%</span>
   602→                <span style={{ fontWeight: 600 }}>{Math.round((paidCount / students.length) * 100)}% שולם</span>
   603→                <span>100%</span>
   604→              </div>
   605→            </>
   606→          )}
   607→
   608→          {filtered.map(s => (
   609→            editId === s.id ? (
   610→              <Card key={s.id} style={{ border: "2px solid #ede9fe" }}>
   611→                <div style={{ fontWeight: 700, marginBottom: 10, fontSize: 14 }}>✏️ עריכת תלמיד</div>
   612→                <FieldLabel>שם</FieldLabel>
   613→                <input value={editForm.name} onChange={e => setEditForm({ ...editForm, name: e.target.value })} style={S.input} autoFocus />
   614→                <FieldLabel>סכום ששולם ₪</FieldLabel>
   615→                <input type="number" value={editForm.amount} onChange={e => setEditForm({ ...editForm, amount: e.target.value })} style={S.input} />
   616→                <FieldLabel>הערה</FieldLabel>
   617→                <input value={editForm.note || ""} onChange={e => setEditForm({ ...editForm, note: e.target.value })} placeholder="הערה..." style={S.input} />
   618→                <label style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 12, cursor: "pointer", fontSize: 13 }}>
   619→                  <input type="checkbox" checked={!!editForm.paid} onChange={e => setEditForm({ ...editForm, paid: e.target.checked })} style={{ width: 16, height: 16 }} />
   620→                  שולם ✅
   621→                </label>
   622→                <div style={{ display: "flex", gap: 8 }}>
   623→                  <button onClick={saveEdit} style={S.btn("#7c3aed")}>שמור</button>
   624→                  <button onClick={cancelEdit} style={S.btn("#94a3b8")}>ביטול</button>
   625→                </div>
   626→              </Card>
   627→            ) : (
   628→              <div key={s.id} style={{
   629→                background: "white", borderRadius: 14, padding: "12px 14px", marginBottom: 8,
   630→                boxShadow: "0 2px 10px rgba(0,0,0,0.06)",
   631→                borderRight: `4px solid ${s.paid ? "#059669" : "#e2e8f0"}`,
   632→              }}>
   633→                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
   634→                  <div style={{ flex: 1 }}>
   635→                    <div style={{ fontWeight: 700, fontSize: 14, color: "#0f172a" }}>
   636→                      {students.indexOf(s) + 1}. {s.name}
   637→                    </div>
   638→                    {s.note && <div style={{ fontSize: 11, color: "#f59e0b", marginTop: 2 }}>📝 {s.note}</div>}
   639→                  </div>
   640→                  <div style={{ display: "flex", alignItems: "center", gap: 8, flexShrink: 0 }}>
   641→                    {s.paid && <span style={{ fontSize: 12, fontWeight: 700, color: "#059669" }}>₪{s.amount}</span>}
   642→                    <button onClick={() => toggle(s.id)} style={{
   643→                      width: 36, height: 36, borderRadius: "50%", border: "none", cursor: "pointer",
   644→                      background: s.paid ? "#dcfce7" : "#fee2e2", fontSize: 18,
   645→                    }}>{s.paid ? "✅" : "❌"}</button>
   646→                  </div>
   647→                </div>
   648→                <div style={{ display: "flex", gap: 6, marginTop: 8 }}>
   649→                  <button onClick={() => startEdit(s)} style={S.smallBtn("#e2e8f0", "#64748b")}>✏️ ערכי</button>
   650→                  <button onClick={() => removeStudent(s.id)} style={S.smallBtn("#fee2e2", "#ef4444")}>✕ מחקי</button>
   651→                </div>
   652→              </div>
   653→            )
   654→          ))}
   655→
   656→          {showAdd ? (
   657→            <Card>
   658→              <FieldLabel>שם התלמיד/ה *</FieldLabel>
   659→              <input value={newName} onChange={e => setNewName(e.target.value)}
   660→                placeholder="שם התלמיד/ה" style={S.input} autoFocus
   661→                onKeyDown={e => e.key === "Enter" && addStudent()} />
   662→              <div style={{ display: "flex", gap: 8 }}>
   663→                <button onClick={addStudent} style={S.btn("#7c3aed")}>הוסיפי</button>
   664→                <button onClick={() => setShowAdd(false)} style={S.btn("#94a3b8")}>ביטול</button>
   665→              </div>
   666→            </Card>
   667→          ) : (
   668→            <button onClick={() => setShowAdd(true)} style={{
   669→              width: "100%", padding: 14, borderRadius: 14, border: "2px dashed #e2e8f0",
   670→              background: "transparent", color: "#7c3aed", fontWeight: 700, fontSize: 14,
   671→              cursor: "pointer", fontFamily: "inherit", marginTop: 4,
   672→            }}>+ הוסיפי תלמיד/ה</button>
   673→          )}
   674→
