   928→
   929→      const paidCount   = budget.students.filter(s => s.paid).length;
   930→      const totalBudget = budget.events.reduce((s, e) => s + e.budget, 0);
   931→      const totalSpent  = budget.events.reduce((s, e) => s + e.spent, 0);
