            ))}
          </div>
          <FieldLabel>שם הרעיון *</FieldLabel>
          <input value={data.name} onChange={e => onChange({ ...data, name: e.target.value })} placeholder="שם הרעיון" style={S.input} autoFocus />
          <FieldLabel>עבור מי</FieldLabel>
          <input value={data.forWhom} onChange={e => onChange({ ...data, forWhom: e.target.value })} placeholder="אנני, כיתה, הורים..." style={S.input} />
          <FieldLabel>טווח מחיר</FieldLabel>
          <input value={data.priceRange} onChange={e => onChange({ ...data, priceRange: e.target.value })} placeholder="50–100₪" style={S.input} />
          <FieldLabel>תג / אירוע</FieldLabel>
          <input value={data.tag} onChange={e => onChange({ ...data, tag: e.target.value })} placeholder="סוף שנה, פורים..." style={S.input} />
          <FieldLabel>הערות</FieldLabel>
          <input value={data.notes} onChange={e => onChange({ ...data, notes: e.target.value })} placeholder="הערות" style={S.input} />
          <div style={{ display: "flex", gap: 8 }}>
            <button onClick={onSave} style={S.btn("#7c3aed")} disabled={!data.name.trim()}>שמור</button>
            <button onClick={onCancel} style={S.btn("#94a3b8")}>ביטול</button>
          </div>
        </Card>
      );

      return (
        <div>
          <input placeholder="🔍 חפשי רעיון..." value={search}
            onChange={e => setSearch(e.target.value)} style={{ ...S.input, marginBottom: 12 }} />

          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10, marginBottom: 12 }}>
            {filtered.map(gift => (
              editId === gift.id ? null : (
                <div key={gift.id} style={{ background: "white", borderRadius: 16, padding: 14, boxShadow: "0 2px 14px rgba(0,0,0,0.08)" }}>
                  <div style={{ fontSize: 30, marginBottom: 6 }}>{gift.icon}</div>
                  <div style={{ fontWeight: 700, fontSize: 13, color: "#0f172a", marginBottom: 4 }}>{gift.name}</div>
                  {gift.forWhom   && <div style={{ fontSize: 11, color: "#94a3b8", marginBottom: 2 }}>עבור: {gift.forWhom}</div>}
                  {gift.notes     && <div style={{ fontSize: 11, color: "#64748b", marginBottom: 4 }}>{gift.notes}</div>}
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginTop: 4, marginBottom: 8 }}>
                    {gift.tag       && <span style={{ fontSize: 10, fontWeight: 700, background: "#f0fdf4", color: "#059669", borderRadius: 8, padding: "2px 6px" }}>{gift.tag}</span>}
                    {gift.priceRange && <span style={{ fontSize: 12, fontWeight: 700, color: "#7c3aed" }}>{gift.priceRange}</span>}
                  </div>
                  <div style={{ display: "flex", gap: 4 }}>
                    <button onClick={() => startEdit(gift)} style={{ ...S.smallBtn("#e2e8f0", "#64748b"), flex: 1, textAlign: "center" }}>✏️</button>
                    <button onClick={() => removeGift(gift.id)} style={{ ...S.smallBtn("#fee2e2", "#ef4444"), flex: 1, textAlign: "center" }}>✕</button>
                  </div>
                </div>
              )
            ))}
          </div>

          {/* Edit form (full width, below grid) */}
          {editId !== null && (
            <GiftForm title="✏️ עריכת רעיון" data={editForm} onChange={setEditForm} onSave={saveEdit} onCancel={cancelEdit} />
          )}

          {showAdd ? (
            <GiftForm title="➕ רעיון חדש" data={addForm} onChange={setAddForm} onSave={addGift} onCancel={() => setShowAdd(false)} />
          ) : (
            <button onClick={() => setShowAdd(true)} style={{
              width: "100%", padding: 14, borderRadius: 14, border: "2px dashed #e2e8f0",
              background: "transparent", color: "#7c3aed", fontWeight: 700, fontSize: 14,
              cursor: "pointer", fontFamily: "inherit",
            }}>+ הוסיפי רעיון</button>
          )}
        </div>
      );
    }

    // ─────────────────────────────────────────
    // CASH TAB — with edit
    // ─────────────────────────────────────────
    const EMPTY_CASH = { date: "", desc: "", amount: "", type: "income", paidBy: "" };

    function CashTab({ cashLog, setCashLog }) {
      const [showAdd,  setShowAdd]  = useState(false);
      const [addForm,  setAddForm]  = useState(EMPTY_CASH);
      const [editId,   setEditId]   = useState(null);
      const [editForm, setEditForm] = useState({});

      const balance  = cashLog.reduce((s, c) => s + c.amount, 0);
      const totalIn  = cashLog.filter(c => c.amount > 0).reduce((s, c) => s + c.amount, 0);
      const totalOut = cashLog.filter(c => c.amount < 0).reduce((s, c) => s + Math.abs(c.amount), 0);

      const addEntry = () => {
        if (!addForm.desc.trim() || !addForm.amount) return;
        const amt = Number(addForm.amount) * (addForm.type === "expense" ? -1 : 1);
        setCashLog([...cashLog, { id: Date.now(), ...addForm, amount: amt }]);
        setAddForm(EMPTY_CASH); setShowAdd(false);
      };

      const startEdit  = (e) => { setEditId(e.id); setEditForm({ ...e, amount: String(Math.abs(e.amount)), type: e.amount >= 0 ? "income" : "expense" }); };
      const cancelEdit = () => setEditId(null);
      const saveEdit   = () => {
        const amt = Number(editForm.amount) * (editForm.type === "expense" ? -1 : 1);
        setCashLog(cashLog.map(c => c.id === editId ? { ...editForm, id: editId, amount: amt } : c));
        setEditId(null);
      };
      const removeEntry = (id) => { if (window.confirm("למחוק תנועה זו?")) setCashLog(cashLog.filter(c => c.id !== id)); };

      const CashForm = ({ data, onChange, onSave, onCancel, title }) => (
        <Card style={{ border: "2px solid #1e293b20" }}>
          <div style={{ fontWeight: 700, marginBottom: 10, fontSize: 14 }}>{title}</div>
          <div style={{ display: "flex", gap: 8, marginBottom: 8 }}>
            {["income", "expense"].map(t => (
              <button key={t} onClick={() => onChange({ ...data, type: t })} style={{
                flex: 1, padding: "10px 0", borderRadius: 10, border: "none",
                cursor: "pointer", fontFamily: "inherit", fontWeight: 700, fontSize: 13,
                background: data.type === t ? (t === "income" ? "#dcfce7" : "#fee2e2") : "#f1f5f9",
                color:      data.type === t ? (t === "income" ? "#059669" : "#ef4444") : "#94a3b8",
              }}>{t === "income" ? "✅ הכנסה" : "📤 הוצאה"}</button>
            ))}
          </div>
          <FieldLabel>תיאור *</FieldLabel>
          <input value={data.desc} onChange={e => onChange({ ...data, desc: e.target.value })} placeholder="תיאור" style={S.input} autoFocus />
          <div style={{ display: "flex", gap: 8 }}>
            <div style={{ flex: 1 }}>
              <FieldLabel>סכום ₪ *</FieldLabel>
              <input type="number" value={data.amount} onChange={e => onChange({ ...data, amount: e.target.value })} placeholder="0" style={S.input} />
            </div>
            <div style={{ flex: 1 }}>
              <FieldLabel>תאריך</FieldLabel>
              <input value={data.date} onChange={e => onChange({ ...data, date: e.target.value })} placeholder="01.01.25" style={S.input} />
            </div>
          </div>
          <FieldLabel>שולם ע״י (אופציונלי)</FieldLabel>
          <input value={data.paidBy || ""} onChange={e => onChange({ ...data, paidBy: e.target.value })} placeholder="שם" style={S.input} />
          <div style={{ display: "flex", gap: 8 }}>
            <button onClick={onSave} style={S.btn("#0f172a")} disabled={!data.desc.trim() || !data.amount}>שמור</button>
            <button onClick={onCancel} style={S.btn("#94a3b8")}>ביטול</button>
          </div>
        </Card>
      );

      // running balance
      let running = 0;
      const withBal = cashLog.map(c => { running += c.amount; return { ...c, bal: running }; });

      return (
        <div>
          {/* Balance card */}
          <div style={{
            background: "linear-gradient(135deg,#1e293b,#0f172a)",
            borderRadius: 20, padding: 20, color: "white", marginBottom: 16,
          }}>
            <div style={{ opacity: 0.6, fontSize: 13, marginBottom: 4 }}>יתרת מזומן</div>
            <div style={{ fontSize: 36, fontWeight: 900, letterSpacing: -1 }}>
              {balance < 0 ? "-" : ""}₪{Math.abs(balance).toLocaleString()}
            </div>
            <div style={{ display: "flex", gap: 24, marginTop: 12 }}>
              <div><div style={{ opacity: 0.5, fontSize: 11 }}>נכנס סה״כ</div><div style={{ fontWeight: 700, color: "#4ade80" }}>+₪{totalIn.toLocaleString()}</div></div>
              <div><div style={{ opacity: 0.5, fontSize: 11 }}>יצא סה״כ</div><div style={{ fontWeight: 700, color: "#f87171" }}>-₪{totalOut.toLocaleString()}</div></div>
            </div>
          </div>

          <h3 style={{ fontWeight: 800, fontSize: 15, color: "#1e293b", marginBottom: 10 }}>יומן תנועות</h3>

          {[...withBal].reverse().map(entry => (
            editId === entry.id ? (
              <CashForm key={entry.id} title="✏️ עריכת תנועה" data={editForm} onChange={setEditForm} onSave={saveEdit} onCancel={cancelEdit} />
            ) : (
              <div key={entry.id} style={{
                background: "white", borderRadius: 12, padding: "12px 14px", marginBottom: 8,
                boxShadow: "0 2px 10px rgba(0,0,0,0.06)",
                borderRight: `4px solid ${entry.amount > 0 ? "#4ade80" : "#f87171"}`,
              }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                  <div style={{ flex: 1 }}>
                    <div style={{ fontWeight: 600, fontSize: 14, color: "#0f172a" }}>{entry.desc}</div>
                    <div style={{ fontSize: 11, color: "#94a3b8", marginTop: 2 }}>
                      {entry.date}{entry.paidBy && ` • ${entry.paidBy}`}
                    </div>
                  </div>
                  <div style={{ textAlign: "left", flexShrink: 0 }}>
                    <div style={{ fontWeight: 800, fontSize: 15, color: entry.amount > 0 ? "#059669" : "#ef4444" }}>
                      {entry.amount > 0 ? "+" : ""}₪{Math.abs(entry.amount).toLocaleString()}
                    </div>
                    <div style={{ fontSize: 10, color: "#94a3b8" }}>יתרה ₪{entry.bal.toLocaleString()}</div>
                  </div>
                </div>
                <div style={{ display: "flex", gap: 6, marginTop: 8 }}>
                  <button onClick={() => startEdit(entry)} style={S.smallBtn("#e2e8f0", "#64748b")}>✏️ ערכי</button>
                  <button onClick={() => removeEntry(entry.id)} style={S.smallBtn("#fee2e2", "#ef4444")}>✕ מחקי</button>
                </div>
              </div>
            )
          ))}

          {showAdd ? (
            <CashForm title="➕ תנועה חדשה" data={addForm} onChange={setAddForm} onSave={addEntry} onCancel={() => setShowAdd(false)} />
          ) : (
            <button onClick={() => setShowAdd(true)} style={{
              width: "100%", padding: 14, borderRadius: 14, border: "2px dashed #e2e8f0",
              background: "transparent", color: "#0f172a", fontWeight: 700, fontSize: 14,
              cursor: "pointer", fontFamily: "inherit", marginTop: 4,
            }}>+ רשמי תנועה</button>
          )}
        </div>
      );
    }

    // ─────────────────────────────────────────
    // BUDGET SCREEN — 4-tab layout for a single budget
    // ─────────────────────────────────────────
    function BudgetScreen({ budget, onUpdate, onBack, activeTab, setActiveTab }) {
      const clr = BUDGET_COLORS[budget.colorKey] || BUDGET_COLORS.purple;

      const setStudents = (students) => onUpdate({ students });
      const setEvents   = (events)   => onUpdate({ events });
      const setCashLog  = (cashLog)  => onUpdate({ cashLog });
      const setGifts    = (gifts)    => onUpdate({ gifts });

      const paidCount   = budget.students.filter(s => s.paid).length;
      const totalBudget = budget.events.reduce((s, e) => s + e.budget, 0);
      const totalSpent  = budget.events.reduce((s, e) => s + e.spent, 0);
      const balance     = budget.cashLog.reduce((s, c) => s + c.amount, 0);

      return (
        <div style={{ minHeight: "100vh", maxWidth: 480, margin: "0 auto", background: "#f8fafc", fontFamily: "'Heebo', sans-serif", direction: "rtl" }}>
          {/* Header */}
          <div style={{
            background: `linear-gradient(135deg, ${clr.from} 0%, ${clr.to} 100%)`,
            padding: "14px 16px 52px", position: "relative", overflow: "hidden",
          }}>
            <div style={{ position: "absolute", top: -40, left: -20, width: 150, height: 150, borderRadius: "50%", background: "rgba(255,255,255,0.07)" }} />
            <button onClick={onBack} style={{
              background: "rgba(255,255,255,0.2)", border: "none", borderRadius: 10,
              padding: "6px 12px", color: "white", cursor: "pointer", fontFamily: "inherit",
              fontSize: 13, fontWeight: 600, marginBottom: 10, display: "flex", alignItems: "center", gap: 4,
            }}>← כל התקציבים</button>
            <div style={{ color: "white", fontWeight: 900, fontSize: 20, marginBottom: 2 }}>{budget.name}</div>
            <div style={{ color: "rgba(255,255,255,0.75)", fontSize: 13 }}>{budget.className} • {budget.year}</div>
          </div>

          {/* Floating stat cards */}
          <div style={{ display: "flex", gap: 8, padding: "0 14px", marginTop: -34, position: "relative", zIndex: 10, overflowX: "auto", paddingBottom: 4 }}>
            {[
              { icon: "📊", l: "תקציב", v: `₪${totalBudget.toLocaleString()}`, c: clr.from },
              { icon: "✅", l: "שולם",  v: `₪${totalSpent.toLocaleString()}`,  c: "#db2777" },
              { icon: "👧", l: "שילמו", v: budget.students.length > 0 ? `${paidCount}/${budget.students.length}` : "—", c: "#059669" },
              { icon: "💵", l: "מזומן", v: `₪${balance.toLocaleString()}`,      c: "#ea580c" },
            ].map(s => (
              <div key={s.l} style={{
                background: "white", borderRadius: 14, padding: "10px 10px", minWidth: 82,
                boxShadow: "0 4px 18px rgba(0,0,0,0.12)", flex: "0 0 auto", textAlign: "center",
              }}>
                <div style={{ fontSize: 16 }}>{s.icon}</div>
                <div style={{ fontWeight: 900, fontSize: 13, color: s.c, marginTop: 1 }}>{s.v}</div>
                <div style={{ fontSize: 10, color: "#94a3b8" }}>{s.l}</div>
              </div>
            ))}
          </div>

          {/* Tab content */}
          <div style={{ padding: "14px 14px 90px" }}>
            {activeTab === "budget"  && <BudgetTab  events={budget.events}     setEvents={setEvents} />}
            {activeTab === "collect" && <CollectTab students={budget.students} setStudents={setStudents} feePerStudent={budget.feePerStudent} />}
            {activeTab === "gifts"   && <GiftsTab   gifts={budget.gifts}       setGifts={setGifts} />}
            {activeTab === "cash"    && <CashTab     cashLog={budget.cashLog}   setCashLog={setCashLog} />}
          </div>

          <BottomNav tabs={BUDGET_TABS} activeTab={activeTab} setActiveTab={setActiveTab} />
        </div>
      );
    }

    // ─────────────────────────────────────────
    // APP — Root state & routing
    // ─────────────────────────────────────────
    const INITIAL_BUDGETS = [{
      id: 1,
      name: "ועד הורים",
      className: "כיתה ו׳",
      year: "תשפ״ד–תשפ״ה",
      colorKey: "purple",
      feePerStudent: 500,
      students: DEMO_STUDENTS,
      events:   DEMO_EVENTS,
      cashLog:  DEMO_CASH,
      gifts:    DEMO_GIFTS,
    }];

    function App() {
      const [budgets,         setBudgets]         = useState(INITIAL_BUDGETS);
      const [activeBudgetId,  setActiveBudgetId]  = useState(null);
      const [activeTab,       setActiveTab]        = useState("budget");

      const activeBudget = budgets.find(b => b.id === activeBudgetId) || null;

      const updateBudget = useCallback((id, updates) => {
        setBudgets(prev => prev.map(b => b.id === id ? { ...b, ...updates } : b));
      }, []);

      if (!activeBudget) {
        return (
          <HomeScreen
            budgets={budgets}
            setBudgets={setBudgets}
            onSelect={(id) => { setActiveBudgetId(id); setActiveTab("budget"); }}
          />
        );
      }

      return (
        <BudgetScreen
          budget={activeBudget}
          onUpdate={(updates) => updateBudget(activeBudgetId, updates)}
          onBack={() => setActiveBudgetId(null)}
          activeTab={activeTab}
          setActiveTab={setActiveTab}
        />
      );
    }

    ReactDOM.createRoot(document.getElementById('root')).render(<App />);
  </script>
</body>
</html>

