const EMPTY_CASH = { date: "", desc: "", amount: "", type: "income", paidBy: "" };

function CashTab({ cashLog, setCashLog, students = [] }) {
  const [showAdd,  setShowAdd]  = useState(false);
  const [addForm,  setAddForm]  = useState(EMPTY_CASH);
  const [editId,   setEditId]   = useState(null);
