                <div style={{ fontSize: 11, color: "#94a3b8", marginTop: 2 }}>
                  {entry.date}{entry.paidBy && ` • ${entry.paidBy}`}
                </div>
              </div>
              <div style={{ textAlign: "left", flexShrink: 0 }}>
                <div style={{ fontWeight: 800, fontSize: 15, color: entry.amount > 0 ? "#059669" : "#ef4444" }}>
                  {entry.amount > 0 ? "+" : ""}₪{Math.abs(entry.amount).toLocaleString()}
                </div>
                <div style={{ fontSize: 10, color: "#94a3b8" }}>יתרה ₪{entry.bal.toLocaleString()}</div>
              </div>
            </div>
            <div style={{ display: "flex", gap: 6, marginTop: 8 }}>
              <button onClick={() => startEdit(entry)} style={S.smallBtn("#e2e8f0", "#64748b")}>✏️ ערכי</button>
              <button onClick={() => removeEntry(entry.id)} style={S.smallBtn("#fee2e2", "#ef4444")}>✕ מחקי</button>
            </div>
          </div>
        )
      ))}

      {showAdd ? (
        <CashForm title="➕ תנועה חדשה" data={addForm} onChange={setAddForm} onSave={addEntry} onCancel={() => setShowAdd(false)} />
      ) : (
        <button onClick={() => setShowAdd(true)} style={{
          width: "100%", padding: 14, borderRadius: 14, border: "2px dashed #e2e8f0",
          background: "transparent", color: "#0f172a", fontWeight: 700, fontSize: 14,
          cursor: "pointer", fontFamily: "inherit", marginTop: 4,
        }}>+ רשמי תנועה</button>
      )}
    </div>
  );
}

